SELECT country_id, SUM(solar_capacity) AS total_solar_capacity
FROM renewable_energy_data
GROUP BY country_id;

SELECT total_energy_consumption, energy_efficiency
FROM energy_statistics
WHERE year = 2020;

SELECT solar_capacity, wind_capacity
FROM renewable_energy_data
WHERE year = 2020;

SELECT AVG(dependency_percent) AS avg_dependency_percent, year
FROM dependency_data
WHERE year = 2020;

SELECT SUM(total_energy_consumption) AS total_energy_consumption_2020
FROM energy_statistics
WHERE year = 2020;
